3	function PageLoad() {
4	  $("body").removeClass("hidden");
5	  TweenMax.to($(".preloader-text"), 1, {
6	    force3D: true,
7	    opacity: 1,
8	    y: 0,
9	    delay: 0.2,
10	    ease: Power3.easeOut,
11	  });
12	
13	  var width = 100,
14	    perfData = window.performance.timing,
15	    EstimatedTime = -(perfData.loadEventEnd - perfData.navigationStart),
16	    time = parseInt((EstimatedTime / 500) % 50) * 70;
17	
18	  // Percentage Increment Animation
19	  var PercentageID = $("#precent"),
20	    start = 1,
21	    end = 100,
22	    durataion = time;
23	  animateValue(PercentageID, start, end, durataion);
24	
25	  function animateValue(id, start, end, duration) {
26	    var range = end - start,
27	      current = start,
28	      increment = end > start ? 1 : -1,
29	      stepTime = Math.abs(Math.floor(duration / range)),
30	      obj = $(id);
31	
32	    var timer = setInterval(function () {
33	      current += increment;
34	      $(obj).text(current);
35	      if (current === end) {
36	        clearInterval(timer);
37	      }
38	    }, stepTime);
39	  }
40	  // Fading Out Loadbar on Finised
41	  setTimeout(function () {
42	    TweenMax.to($(".percentage, .inner"), 0.7, {
43	      force3D: true,
44	      opacity: 0,
45	      yPercent: -101,
46	      ease: Power3.easeInOut,
47	    });
48	    TweenMax.to($(".preloader-wrap"), 0.7, {
49	      force3D: true,
50	      yPercent: -150,
51	      delay: 0.2,
52	      ease: Power3.easeInOut,
53	    });
54	  }, time);
55	}
