input.payload:
(() => {
  const img = document.querySelector('.about_content-thumb-image img');
  const canvas = document.createElement('canvas');
  canvas.width = img.naturalWidth; canvas.height = img.naturalHeight;
  const ctx = canvas.getContext('2d');
  ctx.drawImage(img, 0, 0);
  const d = ctx.getImageData(300, 400, 1, 1).data;
  const maskStyle = img.style.webkitMask || img.getAttribute('style');
  return JSON.stringify({pixelAtCenter: Array.from(d), maskStyleAttr: maskStyle});
})()

