(async () => {
  const [prod, prev] = await Promise.all([
    fetch('https://coaching.begbie.com/', {cache: 'no-store'}).then(r => r.text()),
    fetch('https://chore-refresh-profile-photos.begbie-hugo.pages.dev/', {cache: 'no-store'}).then(r => r.text())
  ]);
  const extract = (html) => {
    const idx = html.indexOf('bundle.min');
    return html.slice(idx - 60, idx + 80);
  };
  return JSON.stringify({prodScriptTag: extract(prod), previewScriptTag: extract(prev), prodLen: prod.length, prevLen: prev.length});
})()

(async () => {
  const [prod, prev] = await Promise.all([
    fetch('https://coaching.begbie.com/', {cache: 'no-store'}).then(r => r.text()),
    fetch('https://chore-refresh-profile-photos.begbie-hugo.pages.dev/', {cache: 'no-store'}).then(r => r.text())
  ]);
  // find first index where they diverge
  let i = 0;
  const minLen = Math.min(prod.length, prev.length);
  while (i < minLen && prod[i] === prev[i]) i++;
  return JSON.stringify({
    divergeAt: i,
    prodContext: prod.slice(Math.max(0,i-150), i+150),
    prevContext: prev.slice(Math.max(0,i-150), i+150)
  });
})()

(async () => {
  const prod = await fetch('https://coaching.begbie.com/', {cache: 'no-store'}).then(r => r.text());
  const rocketIdx = prod.indexOf('rocket-loader');
  const cdnCgiIdx = prod.indexOf('cdn-cgi');
  return JSON.stringify({
    hasRocketLoaderText: rocketIdx !== -1,
    rocketLoaderContext: rocketIdx !== -1 ? prod.slice(rocketIdx-100, rocketIdx+150) : null,
    hasCdnCgi: cdnCgiIdx !== -1,
    cdnCgiContext: cdnCgiIdx !== -1 ? prod.slice(cdnCgiIdx-50, cdnCgiIdx+200) : null
  });
})()

