  // search all elements for bluesky reference
  const all = Array.from(document.querySelectorAll('[data-icon], use')).filter(e => (e.getAttribute('data-icon')||'').includes('bluesky') || (e.getAttribute('href')||'').includes('bluesky') || (e.getAttribute('xlink:href')||'').includes('bluesky'));
