(() => {
  const all = Array.from(document.querySelectorAll('svg[data-icon]'));
  const uniq = {};
  all.forEach(s => { const k = s.getAttribute('data-icon'); if(!uniq[k]) uniq[k] = s.getAttribute('viewBox'); });
  return JSON.stringify(uniq);
})()

